import { Initializer } from '@adobe-commerce/elsie/lib';
import { Lang } from '@adobe-commerce/elsie/i18n';
import { events } from '@adobe-commerce/event-bus';
import {fetchPersonalizationData, getStoreConfig, savePersonalizationData} from '@/personalization/api';

type ConfigProps = {
  langDefinitions?: Lang;
};

const REQUIRE_UPDATE_KEY = 'DROPIN__PERSONALIZATION__REQUIRE_UPDATE__DATA';
const AUTH_KEY = 'DROPIN__PERSONALIZATION__AUTH';

const updatePersonalizationData = async (cartId: string) => {
  const data = await fetchPersonalizationData(cartId);
  if (data !== null) {
    savePersonalizationData(data);
  }
};

const isEnabled = async () => {
  const config = await getStoreConfig();
  return config?.shareActiveSegments && config.shareCustomerGroup && config.shareAppliedCartRule;
};

export const initialize = new Initializer<ConfigProps>({
  init: async (config) => {
    const defaultConfig = {};

    initialize.config.setConfig({ ...defaultConfig, ...config });
  },

  listeners: () => [
    events.on('authenticated', async (authenticated) => {
      const enabled = await isEnabled();
      if (!enabled) {
        return;
      }
      const storedAuth = sessionStorage.getItem(AUTH_KEY);
      if (storedAuth !== null && ((storedAuth === 'true') === authenticated)) {
        return;
      }
      if (authenticated) {
        localStorage.setItem(REQUIRE_UPDATE_KEY, 'true');
        sessionStorage.setItem(AUTH_KEY, 'true');
      } else {
        sessionStorage.setItem(AUTH_KEY, 'false');
        savePersonalizationData({
          segments: [],
          groups: [],
          cartRules: [],
        });
      }
    }, { eager: true }),
    events.on('cart/updated', async (cart) => {
      const enabled = await isEnabled();
      if (cart === null || !enabled) {
        return;
      }
      updatePersonalizationData(cart.id);
    }, { eager: true }),
    events.on('cart/initialized', async (cart) => {
      const enabled = await isEnabled();
      if (cart === null || !enabled) {
        return;
      }
      const value = localStorage.getItem(REQUIRE_UPDATE_KEY);
      const flag = value !== null ? (value === 'true') : false;
      if (flag) {
        updatePersonalizationData(cart.id);
        localStorage.setItem(REQUIRE_UPDATE_KEY, 'false');
      }
    }, { eager: true }),
    events.on('order/placed', async () => {
      const enabled = await isEnabled();
      if (!enabled) {
        return;
      }
      localStorage.setItem(REQUIRE_UPDATE_KEY, 'true');
    }, { eager: true }),
  ],
});

export const config = initialize.config;
