import { fetchGraphQl } from '@/personalization/api';
import { PersonalizationData } from '@/personalization/data/models';
import { transformVisitorData } from '@/personalization/data/transforms';
import { handleFetchError } from '@/personalization/lib/fetch-error';

import { PERSONALIZATION_DATA_QUERY } from './graphql/PersonalizationDataQuery';

export const fetchPersonalizationData = async (cartId: string): Promise<PersonalizationData | null> => {
  return fetchGraphQl(PERSONALIZATION_DATA_QUERY, {
    variables: { cartId }
  }).then(({ errors, data }) => {
    if (errors) return handleFetchError(errors);

    return transformVisitorData(data);
  });
};
