import { PersonalizationData } from '@/personalization/data/models';

export function transformVisitorData(data: any): PersonalizationData {
  if (!data) return {
    groups: [],
    segments: [],
    cartRules: []
  };

  return {
    groups: [data.customerGroup.uid],
    segments: transformItems(data.customerSegments),
    cartRules: transformItems(data.cart.rules),
  };
}

function transformItems(data: any): string[] {
  if (!data.length) return [];

  return data.map((item: any) => (item.uid));
}
