import { PersonalizationData } from '@/personalization/data/models';
import { resetTypes } from "@/personalization/lib/type-registry";
import { events } from "@adobe-commerce/event-bus";
import { getCookie, setCookie } from "@/personalization/lib/cookieUtils";

export const savePersonalizationData = async (data: PersonalizationData): Promise<void> => {
  resetTypes();
  const currentData = getCookie()
  const newData = JSON.stringify(data);
  if (currentData !== newData) {
    await setCookie(newData);
    events.emit('personalization/updated', data);
  }
}
